import DataService from '../../services/DataService';

let leftsearchSchema = [

    {
        fieldName: 'SEARCH BY',
        fieldType: "ddl-radio",
        fieldIcon: "fa fa-user-tie",
        paramName: "SEARCH_BY",
        fieldSearchConditionName: ['SEARCH_BY'],
        isSearch: false,
        value: "",
        listOptions: []
    },
    {
        fieldName: 'INTEGRATIONS',
        fieldType: "ddl-check",
        fieldIcon: "fa fa-user-tie",
        paramName: "INTEGRATIONS",
        fieldSearchConditionName: ['INTEGRATIONS'],
        isSearch: false,
        value: "",
        listOptions: []
    },
    {
        fieldName: 'DATE FROM',
        fieldType: "date",
        fieldIcon: "fa fa-calendar",
        paramName: "DATE_FROM",
        fieldSearchConditionName: ['DATE_FROM'],
        isSearch: false,
        datePickerConfig: {

            useCurrent: false,
            showClear: true,
            showClose: true,
            allowInputToggle: true,
            widgetPositioning: {
                horizontal: 'right',
                vertical: 'bottom'
            }
        },
        value: "",
        listOptions: []
    },
    {
        fieldName: 'DATE TO',
        fieldType: "date",
        fieldIcon: "fa fa-calendar",
        paramName: "DATE_TO",
        fieldSearchConditionName: ['DATE_TO'],
        isSearch: false,
        datePickerConfig: {

            useCurrent: false,
            showClear: true,
            showClose: true,
            allowInputToggle: true,
            widgetPositioning: {
                horizontal: 'right',
                vertical: 'bottom'
            }
        },
        value: "",
        listOptions: []
    },

]

function bindleftCommonSearchdropdown(instance, FilterName) {
    debugger
    var vm = instance;

    var params = `Type=${FilterName}`

    vm.isLoading = true;

    DataService.IntegrationListingFieldData(params).then(response => {

        if (response.data !== null) {

            var json = response.data;

            if (FilterName == 'SEARCH_BY') {
                vm.leftsearchSchema[0].listOptions = json.map((item) => {
                    const container = {};
                    container.name = item.module_name;
                    container.value = item.module_id.toString();
                    return container;
                })

            }
            else if (FilterName == 'INTEGRATION') {
                vm.leftsearchSchema[1].listOptions = json.map((item) => {
                    const container = {};
                    container.name = item.integration_name;
                    container.value = item.integration_id.toString();
                    return container;
                })

            }


        }
    })
}

export default { leftsearchSchema, bindleftCommonSearchdropdown };